#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_TIME 1000
#define MAX_ROWS 50
#define MAX_COLS 50

int minTime[MAX_ROWS][MAX_COLS];
int visited[MAX_ROWS][MAX_COLS];

int bfs(int rows, int cols, int startRow, int startCol, int startTime, int destRow, int destCol) {
    // Initialize the queue with the starting station
    int queue[MAX_TIME * MAX_ROWS * MAX_COLS][3];
    int front = 0, rear = 0;
    queue[rear][0] = startRow;
    queue[rear][1] = startCol;
    queue[rear][2] = startTime;
    rear++;

    // Mark the starting station as visited
    visited[startRow][startCol] = 1;

    while (front < rear) {
        int currRow = queue[front][0];
        int currCol = queue[front][1];
        int currTime = queue[front][2];
        front++;

        // If the current station is the destination, return the time
        if (currRow == destRow && currCol == destCol) {
            return currTime;
        }

        // Explore all possible paths from the current station
        for (int i = 0; i < rows; i++) {
            for (int j = 0; j < cols; j++) {
                // Check if the station is reachable and not visited
                if (i == currRow && abs(j - currCol) == 1 && !visited[i][j]) {
                    // Calculate the time to reach the station
                    int time = currTime + (j > currCol ? 1 : -1);

                    // Mark the station as visited and add it to the queue
                    visited[i][j] = 1;
                    queue[rear][0] = i;
                    queue[rear][1] = j;
                    queue[rear][2] = time;
                    rear++;
                }
            }
        }
    }

    // If the destination is not reachable, return -1
    return -1;
}

