        char type;
        scanf(" %c %d", &type, &trainTime[i][0]);
        if (type == 'F') {
            trainType[i][0] = 1;
        } else if (type == 'O') {
            trainType[i][0] = 2;
        } else {
            trainType[i][0] = 3;
        }
    }
    for (int j = 0; j < cols; j++) {
        char type;
        scanf(" %c %d", &type, &trainTime[0][j]);
        if (type == 'F') {
            trainType[0][j] = 1;
        } else if (type == 'O') {
            trainType[0][j] = 2;
        } else {
            trainType[0][j] = 3;
