import java.util.LinkedList;
import java.util.Queue;
import java.util.Scanner;

public class Main {
    static final int MAX_TIME = 1000;
    static final int MAX_ROWS = 50;
    static final int MAX_COLS = 50;

    static class Station {
        int row, col, time;

        public Station(int row, int col, int time) {
            this.row = row;
            this.col = col;
            this.time = time;
        }
    }

    public static int bfs(int rows, int cols, int startRow, int startCol, int startTime, int destRow, int destCol) {
        // Initialize the queue with the starting station
        Queue<Station> q = new LinkedList<>();
        q.add(new Station(startRow, startCol, startTime));

        // Create a visited matrix
        boolean[][] visited = new boolean[rows][cols];
        visited[startRow][startCol] = true;

        while (!q.isEmpty()) {
            Station curr = q.poll();

            // If the current station is the destination, return the time
            if (curr.row == destRow && curr.col == destCol) {
                return curr.time;
            }

            // Explore all possible paths from the current station
            for (int i = 0; i < rows; i++) {
                for (int j = 0; j < cols; j++) {
                    // Check if the station is reachable and not visited
                    if (i == curr.row && Math.abs(j - curr.col) == 1 && !visited[i][j]) {
                        // Calculate the time to reach the station
                        int time = curr.time + (j > curr.col ? 1 : -1);

                        // Mark the station as visited and add it to the queue
                        visited[i][j] = true;
                        q.add(new Station(i, j, time));
                    }
                }
            }
        }

        // If the destination is not reachable, return -1
        return -1;
    }

